        <style>{`
          @keyframes popupFade {
            from { opacity: 0; transform: translateY(-50%) scale(0.95); }
            to { opacity: 1; transform: translateY(-50%) scale(1); }
          }
          
          @keyframes logoStop {
            0% { transform: translate(-50%, -50%) scale(1); filter: drop-shadow(0 0 0px rgba(255, 222, 66, 0)); }
            50% { transform: translate(-50%, -50%) scale(1.3); filter: drop-shadow(0 0 25px rgba(255, 222, 66, 0.9)); }
            100% { transform: translate(-50%, -50%) scale(1); filter: drop-shadow(0 0 0px rgba(255, 222, 66, 0)); }
          }
          
          .animate-logo-stop {
            animation: logoStop 0.6s cubic-bezier(0.68, -0.55, 0.265, 1.55);
          }
          
          .line-clamp-2 {
            display: -webkit-box;
            -webkit-line-clamp: 2;
            -webkit-box-orient: vertical;
            overflow: hidden;
          }
          
          .line-clamp-3 {
            display: -webkit-box;
            -webkit-line-clamp: 3;
            -webkit-box-orient: vertical;
            overflow: hidden;
          }
          
          .animate-in {
            animation: fadeIn 0.8s ease-out forwards;
          }
          
          @keyframes fadeIn {
            from { opacity: 0; transform: translateY(20px); }
            to { opacity: 1; transform: translateY(0); }
          }
        `}</style>
